#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 200005
#define MAX_LEN 200005
// Define the structure for the Trie node
typedef struct TrieNode {
    struct TrieNode* children[26];
    int isBlocked;
} TrieNode;
// Function to create a new Trie node
TrieNode* createNode() {
    TrieNode* newNode = (TrieNode*) malloc(sizeof(TrieNode));
    for (int i = 0; i < 26; i++) {
        newNode->children[i] = NULL;
    }
    newNode->isBlocked = 0;
    return newNode;
}
// Function to insert a word into the Trie
void insert(TrieNode* root, char* word, int isBlocked) {
    TrieNode* current = root;
    for (int i = 0; i < strlen(word); i++) {
        int index = word[i] - 'a';
        if (current->children[index] == NULL) {
            current->children[index] = createNode();
        }
        current = current->children[index];
    }
    current->isBlocked = isBlocked;
}
// Function to find the shortest prefix
void findPrefix(TrieNode* root, char* word, char* prefix) {
    TrieNode* current = root;
    for (int i = 0; i < strlen(word); i++) {
        int index = word[i] - 'a';
        if (current->children[index] != NULL && current->children[index]->isBlocked == 1) {
            prefix[i] = word[i];
            prefix[i + 1] = '\0';
            return;
        }
        current = current->children[index];
    }
}
int main() {
    int N;
    scanf("%d", &N);
    TrieNode* root = createNode();
    char word[MAX_LEN];
    int isBlocked;
    for (int i = 0; i < N; i++) {
        scanf(" %c %s", &isBlocked, word);
        if (isBlocked == '-') {
            isBlocked = 1;
        } else {
            isBlocked = 0;
        }
        insert(root, word, isBlocked);
    }
    // Find the shortest prefixes for blocked sites
    char prefix[MAX_LEN];
    int count = 0;
    for (int i = 0; i < N; i++) {
        scanf(" %c %s", &isBlocked, word);
        if (isBlocked == '-') {
            findPrefix(root, word, prefix);
            printf("%s\n", prefix);
            count++;
        }
    }
    printf("%d\n", count);
    return 0;
}

