// Define the structure for the Trie node
struct TrieNode {
    unordered_map<char, TrieNode*> children;
    bool isBlocked;
};
// Function to create a new Trie node
TrieNode* createNode() {
    TrieNode* newNode = new TrieNode();
    newNode->isBlocked = false;
    return newNode;
}
// Function to insert a word into the Trie
void insert(TrieNode* root, string word, bool isBlocked) {
    TrieNode* current = root;
    for (char c : word) {
        if (current->children.find(c) == current->children.end()) {
            current->children[c] = createNode();
        }
        current = current->children[c];
    }
    current->isBlocked = isBlocked;
}
// Function to find the shortest prefix
string findPrefix(TrieNode* root, string word) {
    TrieNode* current = root;
    string prefix;
    for (char c : word) {
        prefix += c;
        if (current->children.find(c) != current->children.end() && current->children[c]->isBlocked) {
            return prefix;
        }
        current = current->children[c];
    }
    return "";
}
int main() {
    int N;
    cin >> N;
    TrieNode* root = createNode();
    string word;
    bool isBlocked;
    for (int i = 0; i < N; i++) {
        cin >> isBlocked >> word;
        insert(root, word, isBlocked);
    }
    // Find the shortest prefixes for blocked sites
    vector<string> prefixes;
    for (int i = 0; i < N; i++) {
