import java.util.HashMap;
import java.util.Map;
import java.util.Scanner;
public class Main {
    // Define the structure for the Trie node
    static class TrieNode {
        Map<Character, TrieNode> children;
        boolean isBlocked;
        public TrieNode() {
            children = new HashMap<>();
            isBlocked = false;
        }
    }
    // Function to create a new Trie node
    public static TrieNode createNode() {
        return new TrieNode();
    }
    // Function to insert a word into the Trie
    public static void insert(TrieNode root, String word, boolean isBlocked) {
        TrieNode current = root;
        for (char c : word.toCharArray()) {
            if (!current.children.containsKey(c)) {
                current.children.put(c, createNode());
            }
            current = current.children.get(c);
        }
        current.isBlocked = isBlocked;
    }
    // Function to find the shortest prefix
    public static String findPrefix(TrieNode root, String word) {
        TrieNode current = root;
        StringBuilder prefix = new StringBuilder();
        for (char c : word.toCharArray()) {
            prefix.append(c);
            if (current.children.containsKey(c) && current.children.get(c).isBlocked) {
                return prefix.toString();
            }
            current = current.children.get(c);
        }
        return "";
    }
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        scanner.nextLine();
        TrieNode root = createNode();
        for (int i = 0; i < N; i++) {
            String line = scanner.nextLine();
            boolean isBlocked = line.charAt(0) == '-';
            String word = line.substring(2);
            insert(root, word, isBlocked);
        }
        // Find the shortest prefixes for blocked sites
        int count = 0;
        for (int i = 0; i < N; i++) {
            String line = scanner.nextLine();
            boolean isBlocked = line.charAt(0) == '-';
            String word = line.substring(2);
            if (isBlocked) {
                String prefix = findPrefix(root, word);
                if (!prefix.isEmpty()) {
                    System.out.println(prefix);
                    count++;
                }
            }
        }
        System.out.println(count);
    }
}

